/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Exports the contents of a grid (using the selected order and filters) to an Excel file. LoadWWPContext.Call(&Context)
Do 'OpenDocument'
&CellRow = 1 &FirstColumn = 1
Do 'LoadGridState'
Do 'WriteFilters'
Do 'WriteColumnTitles'
Do 'WriteData'
Do 'CloseDocument'
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
Sub 'OpenDocument'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&Random = Random() * 10000 &Filename = !"ExportWWMovimento-" + &Random.ToString().Trim() + !".xlsx"
&ExcelDocument.Open(&Filename) Do 'CheckStatus' &ExcelDocument.Clear()
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'WriteFilters'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
If not (&MovCreDeb.IsEmpty()) WWP_ExportWriteFilter(&ExcelDocument, true, &CellRow, &FirstColumn, "Cré./Déb.") &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = '' do Case Case &MovCreDeb.ToString().Trim() = "C" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = "Crédito"
Case &MovCreDeb.ToString().Trim() = "D" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = "Débito"
EndCase EndIf
If not (&MovTip.IsEmpty()) WWP_ExportWriteFilter(&ExcelDocument, true, &CellRow, &FirstColumn, "Tipo") If Not &MovTip.IsEmpty() &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = &MovTip.EnumerationDescription() Endif EndIf
If not (&MovDtaCon.IsEmpty() AND &MovDtaCon_To.IsEmpty()) WWP_ExportWriteFilter(&ExcelDocument, true, &CellRow, &FirstColumn, "D.") &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Date = &MovDtaCon WWP_ExportWriteFilter(&ExcelDocument, false, &CellRow, &FirstColumn + 2, " - ") &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Date = &MovDtaCon_To EndIf
If not (&MovSts.IsEmpty()) WWP_ExportWriteFilter(&ExcelDocument, true, &CellRow, &FirstColumn, "Status") If Not &MovSts.IsEmpty() &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = &MovSts.EnumerationDescription() Endif EndIf
If not (&MovCtaBanCod.IsEmpty()) WWP_ExportWriteFilter(&ExcelDocument, true, &CellRow, &FirstColumn, "Conta Bancária") &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &MovCtaBanCod EndIf If &GridState.DynamicFilters.Count >= 1 &GridStateDynamicFilter = &GridState.DynamicFilters.Item(1) &DynamicFiltersSelector1 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector1 = !'MOVDOC' &MovDoc1.FromString(&GridStateDynamicFilter.Value) If not &MovDoc1.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Doc." &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&MovDoc1) EndIf Case &DynamicFiltersSelector1 = !'MOVCOD' &MovCod1.FromString(&GridStateDynamicFilter.Value) If not &MovCod1.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Código" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &MovCod1 EndIf Case &DynamicFiltersSelector1 = !'MOVVLR' &DynamicFiltersOperator1 = &GridStateDynamicFilter.Operator &MovVlr1.FromString(&GridStateDynamicFilter.Value) If not &MovVlr1.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 Do Case Case &DynamicFiltersOperator1 = 0 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "Valor", "<") Case &DynamicFiltersOperator1 = 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "Valor", "=") Case &DynamicFiltersOperator1 = 2 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "Valor", ">") EndCase &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &MovVlr1 EndIf Case &DynamicFiltersSelector1 = !'MOVCPLTOT' &MovCplTot1.FromString(&GridStateDynamicFilter.Value) If not &MovCplTot1.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Completo" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&MovCplTot1) EndIf EndCase If &GridState.DynamicFilters.Count >= 2 &DynamicFiltersEnabled2 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(2) &DynamicFiltersSelector2 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector2 = !'MOVDOC' &MovDoc2.FromString(&GridStateDynamicFilter.Value) If not &MovDoc2.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Doc." &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&MovDoc2) EndIf Case &DynamicFiltersSelector2 = !'MOVCOD' &MovCod2.FromString(&GridStateDynamicFilter.Value) If not &MovCod2.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Código" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &MovCod2 EndIf Case &DynamicFiltersSelector2 = !'MOVVLR' &DynamicFiltersOperator2 = &GridStateDynamicFilter.Operator &MovVlr2.FromString(&GridStateDynamicFilter.Value) If not &MovVlr2.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 Do Case Case &DynamicFiltersOperator2 = 0 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "Valor", "<") Case &DynamicFiltersOperator2 = 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "Valor", "=") Case &DynamicFiltersOperator2 = 2 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "Valor", ">") EndCase &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &MovVlr2 EndIf Case &DynamicFiltersSelector2 = !'MOVCPLTOT' &MovCplTot2.FromString(&GridStateDynamicFilter.Value) If not &MovCplTot2.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Completo" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&MovCplTot2) EndIf EndCase If &GridState.DynamicFilters.Count >= 3 &DynamicFiltersEnabled3 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(3) &DynamicFiltersSelector3 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector3 = !'MOVDOC' &MovDoc3.FromString(&GridStateDynamicFilter.Value) If not &MovDoc3.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Doc." &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&MovDoc3) EndIf Case &DynamicFiltersSelector3 = !'MOVCOD' &MovCod3.FromString(&GridStateDynamicFilter.Value) If not &MovCod3.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Código" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &MovCod3 EndIf Case &DynamicFiltersSelector3 = !'MOVVLR' &DynamicFiltersOperator3 = &GridStateDynamicFilter.Operator &MovVlr3.FromString(&GridStateDynamicFilter.Value) If not &MovVlr3.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 Do Case Case &DynamicFiltersOperator3 = 0 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "Valor", "<") Case &DynamicFiltersOperator3 = 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "Valor", "=") Case &DynamicFiltersOperator3 = 2 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "Valor", ">") EndCase &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &MovVlr3 EndIf Case &DynamicFiltersSelector3 = !'MOVCPLTOT' &MovCplTot3.FromString(&GridStateDynamicFilter.Value) If not &MovCplTot3.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Completo" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&MovCplTot3) EndIf EndCase EndIf EndIf EndIf &CellRow += 2
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'WriteColumnTitles'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Text = "Sequência" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = "Contabilizar" &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = "Tipo" &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Text = "Complemento" &ExcelDocument.Cells(&CellRow, &FirstColumn + 4).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 4).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 4).Text = "Documento" &ExcelDocument.Cells(&CellRow, &FirstColumn + 5).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 5).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 5).Text = "Valor"
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'WriteData'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
For each order EmpCod MovCtaBanCod MovDtaCon MovCod when &OrderedBy = 1 order EmpCod MovCtaBanCod (MovDtaCon) (MovCod) when &OrderedBy = 2 order MovCod when &OrderedBy = 3 AND &OrderedDsc = False order (MovCod) when &OrderedBy = 3 AND &OrderedDsc = True order MovDtaCon when &OrderedBy = 4 AND &OrderedDsc = False order (MovDtaCon) when &OrderedBy = 4 AND &OrderedDsc = True order MovDoc when &OrderedBy = 5 AND &OrderedDsc = False order (MovDoc) when &OrderedBy = 5 AND &OrderedDsc = True order MovVlr when &OrderedBy = 6 AND &OrderedDsc = False order (MovVlr) when &OrderedBy = 6 AND &OrderedDsc = True
using DSWWMovimento(&MovCreDeb, &MovTip, &MovDtaCon, &MovDtaCon_To, &MovSts, &MovCtaBanCod , &DynamicFiltersSelector1, &DynamicFiltersOperator1, &MovDoc1, &MovCod1, &MovVlr1, &MovCplTot1 , &DynamicFiltersEnabled2, &DynamicFiltersSelector2, &DynamicFiltersOperator2, &MovDoc2, &MovCod2, &MovVlr2 , &MovCplTot2, &DynamicFiltersEnabled3, &DynamicFiltersSelector3, &DynamicFiltersOperator3, &MovDoc3, &MovCod3 , &MovVlr3, &MovCplTot3)
// Write cell values &CellRow += 1
Do 'BeforeWriteLine' &ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Number = MovCod &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Date = MovDtaCon &gridMovTip = MovTip &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = &gridMovTip.EnumerationDescription() &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Text = WWP_Export_SecureText(MovCplTot) &ExcelDocument.Cells(&CellRow, &FirstColumn + 4).Text = WWP_Export_SecureText(MovDoc) &ExcelDocument.Cells(&CellRow, &FirstColumn + 5).Number = MovVlr
Do 'AfterWriteLine'
Endfor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'CloseDocument'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&ExcelDocument.Save() Do 'CheckStatus' &ExcelDocument.Close()
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'CheckStatus'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
If (&ExcelDocument.ErrCode <> 0) &Filename = "" &ErrorMessage = &ExcelDocument.ErrDescription &ExcelDocument.Close() Return EndIf
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'LoadGridState'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Load grid state from session. If &Session.Get(!"WWMovimentoGridState") = !"" &GridState.FromXml(LoadGridState.Udp(!"WWMovimentoGridState")) Else &GridState.FromXml(&Session.Get(!"WWMovimentoGridState")) Endif
&OrderedBy = &GridState.OrderedBy &OrderedDsc = &GridState.OrderedDsc
For &GridStateFilterValue in &GridState.FilterValues Do Case Case &GridStateFilterValue.Name = !"MOVCREDEB" &MovCreDeb.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"MOVTIP" &MovTip.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"MOVDTACON" &MovDtaCon.FromString(&GridStateFilterValue.Value) &MovDtaCon_To.FromString(&GridStateFilterValue.ValueTo) Case &GridStateFilterValue.Name = !"MOVSTS" &MovSts.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"MOVCTABANCOD" &MovCtaBanCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PARM_&AUXMOVCTABANCOD" &AuxMovCtaBanCod.FromString(&GridStateFilterValue.Value) EndCase EndFor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'BeforeWriteLine'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'AfterWriteLine'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub

